diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..a26ac2b59ebd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -687,10 +687,81 @@ static Value *foldLogOpOfMaskedICmps(Value *LHS, Value *RHS, bool IsAnd,
         return Builder.CreateICmp(CC, NewAnd, CEVal);
       };

-      if (Mask & BMask_Mixed)
-        return FoldBMixed(NewCC, false);
-      if (Mask & BMask_NotMixed) // can be else also
-        return FoldBMixed(NewCC, true);
+      if (Mask & BMask_Mixed) {
+        if (Value *V = FoldBMixed(NewCC, false))
+          return V;
+      }
+      if (Mask & BMask_NotMixed) {
+        if (Value *V = FoldBMixed(NewCC, true))
+          return V;
+        // Try to fold (A == C) | ((A & M) == E) into a range check.
+        // When one side is a simple equality (mask is all-ones) and the other
+        // is a masked equality, we can sometimes merge them into a single
+        // range check. E.g., (A == 127) | ((A & -32) == 128) -> (A-127) < 33.
+        // Also handle the AND variant:
+        //   (A != C) & ((A & M) != E) -> (A - (RangeHi+1)) u< (-Size)
+        if (((!IsAnd && PredL == ICmpInst::ICMP_EQ &&
+              PredR == ICmpInst::ICMP_EQ) ||
+             (IsAnd && PredL == ICmpInst::ICMP_NE &&
+              PredR == ICmpInst::ICMP_NE))) {
+          const APInt *EqC, *Mask, *MaskedC;
+          Value *MaskedVal;
+          if (ConstB->isAllOnes()) {
+            EqC = OldConstC; Mask = ConstD; MaskedC = OldConstE;
+            MaskedVal = cast<ICmpInst>(RHS)->getOperand(0);
+          } else if (ConstD->isAllOnes()) {
+            EqC = OldConstE; Mask = ConstB; MaskedC = OldConstC;
+            MaskedVal = cast<ICmpInst>(LHS)->getOperand(0);
+          } else {
+            EqC = nullptr;
+          }
+          if (EqC) {
+            // The range formula for ((A & M) == E) -> [E, E | ~M] only
+            // works when M is a negated power of 2 (i.e., clears low bits).
+            if (!Mask->isNegatedPowerOf2())
+              EqC = nullptr;
+            // If the masked value has multiple uses, don't fold.
+            if (EqC && MaskedVal->hasOneUse()) {
+              // The range for ((A & M) == E) is [E, E | ~M].
+              APInt RangeLo = *MaskedC;
+              APInt RangeHi = *MaskedC | ~(*Mask);
+              // Check if the equality constant is adjacent to this range.
+              if (*EqC + 1 == RangeLo) {
+                // EqC is just below: union is [EqC, RangeHi].
+                if (!IsAnd) {
+                  APInt Size = RangeHi - *EqC + 1;
+                  Value *Add = Builder.CreateAdd(
+                      A, ConstantInt::get(A->getType(), -(*EqC)));
+                  return Builder.CreateICmpULT(
+                      Add, ConstantInt::get(A->getType(), Size));
+                } else {
+                  APInt Size = RangeHi - *EqC + 1;
+                  Value *Add = Builder.CreateAdd(
+                      A, ConstantInt::get(A->getType(), -(RangeHi + 1)));
+                  return Builder.CreateICmpULT(
+                      Add, ConstantInt::get(A->getType(), -Size));
+                }
+              }
+              if (RangeHi + 1 == *EqC) {
+                // EqC is just above: union is [RangeLo, EqC].
+                if (!IsAnd) {
+                  APInt Size = *EqC - RangeLo + 1;
+                  Value *Add = Builder.CreateAdd(
+                      A, ConstantInt::get(A->getType(), -RangeLo));
+                  return Builder.CreateICmpULT(
+                      Add, ConstantInt::get(A->getType(), Size));
+                } else {
+                  APInt Size = *EqC - RangeLo + 1;
+                  Value *Add = Builder.CreateAdd(
+                      A, ConstantInt::get(A->getType(), -(*EqC + 1)));
+                  return Builder.CreateICmpULT(
+                      Add, ConstantInt::get(A->getType(), -Size));
+                }
+              }
+            }
+          }
+        }
+      }
     }
   }

